  1	import type { AgentMessage } from "@mariozechner/pi-agent-core";
  2	import type { SessionManager } from "@mariozechner/pi-coding-agent";
  3	
  4	import { makeMissingToolResult } from "./session-transcript-repair.js";
  5	import { emitSessionTranscriptUpdate } from "../sessions/transcript-events.js";
  6	
  7	type ToolCall = { id: string; name?: string };
  8	
  9	function extractAssistantToolCalls(msg: Extract<AgentMessage, { role: "assistant" }>): ToolCall[] {
 10	  const content = msg.content;
 11	  if (!Array.isArray(content)) return [];
 12	
 13	  const toolCalls: ToolCall[] = [];
 14	  for (const block of content) {
 15	    if (!block || typeof block !== "object") continue;
 16	    const rec = block as { type?: unknown; id?: unknown; name?: unknown };
 17	    if (typeof rec.id !== "string" || !rec.id) continue;
 18	    if (rec.type === "toolCall" || rec.type === "toolUse" || rec.type === "functionCall") {
 19	      toolCalls.push({
 20	        id: rec.id,
 21	        name: typeof rec.name === "string" ? rec.name : undefined,
 22	      });
 23	    }
 24	  }
 25	  return toolCalls;
 26	}
 27	
 28	function extractToolResultId(msg: Extract<AgentMessage, { role: "toolResult" }>): string | null {
 29	  const toolCallId = (msg as { toolCallId?: unknown }).toolCallId;
 30	  if (typeof toolCallId === "string" && toolCallId) return toolCallId;
 31	  const toolUseId = (msg as { toolUseId?: unknown }).toolUseId;
 32	  if (typeof toolUseId === "string" && toolUseId) return toolUseId;
 33	  return null;
 34	}
