117	export function extractMessagingToolSend(
118	  toolName: string,
119	  args: Record<string, unknown>,
120	): MessagingToolSend | undefined {
121	  // Provider docking: new provider tools must implement plugin.actions.extractToolSend.
122	  const action = typeof args.action === "string" ? args.action.trim() : "";
123	  const accountIdRaw = typeof args.accountId === "string" ? args.accountId.trim() : undefined;
124	  const accountId = accountIdRaw ? accountIdRaw : undefined;
125	  if (toolName === "message") {
126	    if (action !== "send" && action !== "thread-reply") return undefined;
127	    const toRaw = typeof args.to === "string" ? args.to : undefined;
128	    if (!toRaw) return undefined;
129	    const providerRaw = typeof args.provider === "string" ? args.provider.trim() : "";
130	    const channelRaw = typeof args.channel === "string" ? args.channel.trim() : "";
131	    const providerHint = providerRaw || channelRaw;
132	    const providerId = providerHint ? normalizeChannelId(providerHint) : null;
133	    const provider = providerId ?? (providerHint ? providerHint.toLowerCase() : "message");
134	    const to = normalizeTargetForProvider(provider, toRaw);
135	    return to ? { tool: toolName, provider, accountId, to } : undefined;
136	  }
137	  const providerId = normalizeChannelId(toolName);
138	  if (!providerId) return undefined;
139	  const plugin = getChannelPlugin(providerId);
140	  const extracted = plugin?.actions?.extractToolSend?.({ args });
141	  if (!extracted?.to) return undefined;
142	  const to = normalizeTargetForProvider(providerId, extracted.to);
143	  return to
144	    ? {
145	        tool: toolName,
146	        provider: providerId,
147	        accountId: extracted.accountId ?? accountId,
148	        to,
149	      }
150	    : undefined;
151	}

