  9	function truncateToolText(text: string): string {
 10	  if (text.length <= TOOL_RESULT_MAX_CHARS) return text;
 11	  return `${truncateUtf16Safe(text, TOOL_RESULT_MAX_CHARS)}\n…(truncated)…`;
 12	}
 13	
 14	function normalizeToolErrorText(text: string): string | undefined {
 15	  const trimmed = text.trim();
 16	  if (!trimmed) return undefined;
 17	  const firstLine = trimmed.split(/\r?\n/)[0]?.trim() ?? "";
 18	  if (!firstLine) return undefined;
 19	  return firstLine.length > TOOL_ERROR_MAX_CHARS
 20	    ? `${truncateUtf16Safe(firstLine, TOOL_ERROR_MAX_CHARS)}…`
 21	    : firstLine;
 22	}
 23	
 24	function readErrorCandidate(value: unknown): string | undefined {
 25	  if (typeof value === "string") return normalizeToolErrorText(value);
 26	  if (!value || typeof value !== "object") return undefined;
 27	  const record = value as Record<string, unknown>;
 28	  if (typeof record.message === "string") return normalizeToolErrorText(record.message);
 29	  if (typeof record.error === "string") return normalizeToolErrorText(record.error);
 30	  return undefined;
 31	}
 32	
 33	function extractErrorField(value: unknown): string | undefined {
 34	  if (!value || typeof value !== "object") return undefined;
 35	  const record = value as Record<string, unknown>;
 36	  const direct =
 37	    readErrorCandidate(record.error) ??
 38	    readErrorCandidate(record.message) ??
 39	    readErrorCandidate(record.reason);
 40	  if (direct) return direct;
 41	  const status = typeof record.status === "string" ? record.status.trim() : "";
 42	  return status ? normalizeToolErrorText(status) : undefined;
 43	}
