 87	export function isToolResultError(result: unknown): boolean {
 88	  if (!result || typeof result !== "object") return false;
 89	  const record = result as { details?: unknown };
 90	  const details = record.details;
 91	  if (!details || typeof details !== "object") return false;
 92	  const status = (details as { status?: unknown }).status;
 93	  if (typeof status !== "string") return false;
 94	  const normalized = status.trim().toLowerCase();
 95	  return normalized === "error" || normalized === "timeout";
 96	}
 97	
 98	export function extractToolErrorMessage(result: unknown): string | undefined {
 99	  if (!result || typeof result !== "object") return undefined;
100	  const record = result as Record<string, unknown>;
101	  const fromDetails = extractErrorField(record.details);
102	  if (fromDetails) return fromDetails;
103	  const fromRoot = extractErrorField(record);
104	  if (fromRoot) return fromRoot;
105	  const text = extractToolResultText(result);
106	  if (!text) return undefined;
107	  try {
108	    const parsed = JSON.parse(text) as unknown;
109	    const fromJson = extractErrorField(parsed);
110	    if (fromJson) return fromJson;
111	  } catch {
112	    // Fall through to first-line text fallback.
113	  }
114	  return normalizeToolErrorText(text);
115	}
