 17	function extendExecMeta(toolName: string, args: unknown, meta?: string): string | undefined {
 18	  const normalized = toolName.trim().toLowerCase();
 19	  if (normalized !== "exec" && normalized !== "bash") return meta;
 20	  if (!args || typeof args !== "object") return meta;
 21	  const record = args as Record<string, unknown>;
 22	  const flags: string[] = [];
 23	  if (record.pty === true) flags.push("pty");
 24	  if (record.elevated === true) flags.push("elevated");
 25	  if (flags.length === 0) return meta;
 26	  const suffix = flags.join(" · ");
 27	  return meta ? `${meta} · ${suffix}` : suffix;
 28	}
