139	export function handleToolExecutionEnd(
140	  ctx: EmbeddedPiSubscribeContext,
141	  evt: AgentEvent & {
142	    toolName: string;
143	    toolCallId: string;
144	    isError: boolean;
145	    result?: unknown;
146	  },
147	) {
148	  const toolName = normalizeToolName(String(evt.toolName));
149	  const toolCallId = String(evt.toolCallId);
150	  const isError = Boolean(evt.isError);
151	  const result = evt.result;
152	  const isToolError = isError || isToolResultError(result);
153	  const sanitizedResult = sanitizeToolResult(result);
154	  const meta = ctx.state.toolMetaById.get(toolCallId);
155	  ctx.state.toolMetas.push({ toolName, meta });
156	  ctx.state.toolMetaById.delete(toolCallId);
157	  ctx.state.toolSummaryById.delete(toolCallId);
158	  if (isToolError) {
159	    const errorMessage = extractToolErrorMessage(sanitizedResult);
160	    ctx.state.lastToolError = {
161	      toolName,
162	      meta,
163	      error: errorMessage,
164	    };
165	  }
166	
167	  // Commit messaging tool text on success, discard on error.
168	  const pendingText = ctx.state.pendingMessagingTexts.get(toolCallId);
169	  const pendingTarget = ctx.state.pendingMessagingTargets.get(toolCallId);
170	  if (pendingText) {
171	    ctx.state.pendingMessagingTexts.delete(toolCallId);
172	    if (!isToolError) {
173	      ctx.state.messagingToolSentTexts.push(pendingText);
174	      ctx.state.messagingToolSentTextsNormalized.push(normalizeTextForComparison(pendingText));
175	      ctx.log.debug(`Committed messaging text: tool=${toolName} len=${pendingText.length}`);
176	      ctx.trimMessagingToolSent();
177	    }
178	  }
179	  if (pendingTarget) {
180	    ctx.state.pendingMessagingTargets.delete(toolCallId);
181	    if (!isToolError) {
182	      ctx.state.messagingToolSentTargets.push(pendingTarget);
183	      ctx.trimMessagingToolSent();
184	    }
185	  }
186	
187	  emitAgentEvent({
188	    runId: ctx.params.runId,
189	    stream: "tool",
190	    data: {
191	      phase: "result",
192	      name: toolName,
193	      toolCallId,
194	      meta,
195	      isError: isToolError,
196	      result: sanitizedResult,
197	    },
198	  });
199	  void ctx.params.onAgentEvent?.({
200	    stream: "tool",
201	    data: {
202	      phase: "result",
203	      name: toolName,
204	      toolCallId,
205	      meta,
206	      isError: isToolError,
207	    },
208	  });
209	
210	  ctx.log.debug(
211	    `embedded run tool end: runId=${ctx.params.runId} tool=${toolName} toolCallId=${toolCallId}`,
212	  );
213	
214	  if (ctx.params.onToolResult && ctx.shouldEmitToolOutput()) {
215	    const outputText = extractToolResultText(sanitizedResult);
216	    if (outputText) {
217	      ctx.emitToolOutput(toolName, meta, outputText);
218	    }
219	  }
220	}

