 71	export function repairToolUseResultPairing(messages: AgentMessage[]): ToolUseRepairReport {
 72	  // Anthropic (and Cloud Code Assist) reject transcripts where assistant tool calls are not
 73	  // immediately followed by matching tool results. Session files can end up with results
 74	  // displaced (e.g. after user turns) or duplicated. Repair by:
 75	  // - moving matching toolResult messages directly after their assistant toolCall turn
 76	  // - inserting synthetic error toolResults for missing ids
 77	  // - dropping duplicate toolResults for the same id (anywhere in the transcript)
 78	  const out: AgentMessage[] = [];
 79	  const added: Array<Extract<AgentMessage, { role: "toolResult" }>> = [];
 80	  const seenToolResultIds = new Set<string>();
 81	  let droppedDuplicateCount = 0;
 82	  let droppedOrphanCount = 0;
 83	  let moved = false;
 84	  let changed = false;
 85	
 86	  const pushToolResult = (msg: Extract<AgentMessage, { role: "toolResult" }>) => {
 87	    const id = extractToolResultId(msg);
 88	    if (id && seenToolResultIds.has(id)) {
 89	      droppedDuplicateCount += 1;
 90	      changed = true;
 91	      return;
 92	    }
 93	    if (id) seenToolResultIds.add(id);
 94	    out.push(msg);
 95	  };
 96	
 97	  for (let i = 0; i < messages.length; i += 1) {
 98	    const msg = messages[i] as AgentMessage;
 99	    if (!msg || typeof msg !== "object") {
100	      out.push(msg);
101	      continue;
102	    }
103	
104	    const role = (msg as { role?: unknown }).role;
105	    if (role !== "assistant") {
106	      // Tool results must only appear directly after the matching assistant tool call turn.
107	      // Any "free-floating" toolResult entries in session history can make strict providers
108	      // (Anthropic-compatible APIs, MiniMax, Cloud Code Assist) reject the entire request.
109	      if (role !== "toolResult") {
110	        out.push(msg);
111	      } else {
112	        droppedOrphanCount += 1;
113	        changed = true;
114	      }
115	      continue;
116	    }
117	
118	    const assistant = msg as Extract<AgentMessage, { role: "assistant" }>;
119	    const toolCalls = extractToolCallsFromAssistant(assistant);
120	    if (toolCalls.length === 0) {
121	      out.push(msg);
122	      continue;
123	    }
124	
125	    const toolCallIds = new Set(toolCalls.map((t) => t.id));
126	
127	    const spanResultsById = new Map<string, Extract<AgentMessage, { role: "toolResult" }>>();
128	    const remainder: AgentMessage[] = [];
129	
130	    let j = i + 1;
131	    for (; j < messages.length; j += 1) {
132	      const next = messages[j] as AgentMessage;
133	      if (!next || typeof next !== "object") {
134	        remainder.push(next);
135	        continue;
136	      }
137	
138	      const nextRole = (next as { role?: unknown }).role;
139	      if (nextRole === "assistant") break;
140	
141	      if (nextRole === "toolResult") {
142	        const toolResult = next as Extract<AgentMessage, { role: "toolResult" }>;
143	        const id = extractToolResultId(toolResult);
144	        if (id && toolCallIds.has(id)) {
145	          if (seenToolResultIds.has(id)) {
146	            droppedDuplicateCount += 1;
147	            changed = true;
148	            continue;
149	          }
150	          if (!spanResultsById.has(id)) {
151	            spanResultsById.set(id, toolResult);
152	          }
153	          continue;
154	        }
155	      }
156	
157	      // Drop tool results that don't match the current assistant tool calls.
158	      if (nextRole !== "toolResult") {
159	        remainder.push(next);
160	      } else {
161	        droppedOrphanCount += 1;
162	        changed = true;
163	      }
164	    }
165	
166	    out.push(msg);
167	
168	    if (spanResultsById.size > 0 && remainder.length > 0) {
169	      moved = true;
170	      changed = true;
171	    }
172	
173	    for (const call of toolCalls) {
174	      const existing = spanResultsById.get(call.id);
175	      if (existing) {
176	        pushToolResult(existing);
177	      } else {
178	        const missing = makeMissingToolResult({
179	          toolCallId: call.id,
180	          toolName: call.name,
181	        });
182	        added.push(missing);
183	        changed = true;
184	        pushToolResult(missing);
185	      }
186	    }
187	
188	    for (const rem of remainder) {
189	      if (!rem || typeof rem !== "object") {
190	        out.push(rem);
191	        continue;
192	      }
193	      out.push(rem);
194	    }
195	    i = j - 1;
196	  }
197	
198	  const changedOrMoved = changed || moved;
199	  return {
200	    messages: changedOrMoved ? out : messages,
201	    added,
202	    droppedDuplicateCount,
203	    droppedOrphanCount,
204	    moved: changedOrMoved,
205	  };
206	}

