173	      if (next !== msg) changed = true;
174	      return next;
175	    }
176	    if (role === "toolResult") {
177	      const next = rewriteToolResultIds({
178	        message: msg as Extract<AgentMessage, { role: "toolResult" }>,
179	        resolve,
180	      });
181	      if (next !== msg) changed = true;
182	      return next;
183	    }
184	    return msg;
185	  });
186	
187	  return changed ? out : messages;
188	}

